@RestController
class AuthController {
    private final OidcService oidcService;

    AuthController(OidcService oidcService) {
        this.oidcService = oidcService;
    }

    @GetMapping("/login")
    public void login(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String redirect = oidcService.buildAuthorizationRedirect(request);
        response.sendRedirect(redirect);
    }

    @GetMapping("/oidc/callback")
    public void callback(
            HttpServletRequest request,
            HttpServletResponse response,
            @RequestParam(required = false) String code,
            @RequestParam(required = false) String state,
            @RequestParam(required = false) String error,
            @RequestParam(required = false, name = "error_description") String errorDescription
    ) throws IOException {
        if (error != null) {
            response.setStatus(401);
            response.setContentType("text/plain");
            response.getWriter().write("OIDC error: " + error + (errorDescription != null ? " - " + errorDescription : ""));
            return;
        }

        HttpSession session = request.getSession(false);
        if (session == null) {
            response.setStatus(400);
            response.getWriter().write("Missing session");
            return;
        }

        String expectedState = (String) session.getAttribute("OIDC_STATE");
        if (expectedState == null || !expectedState.equals(state)) {
            response.setStatus(400);
            response.getWriter().write("Invalid state");
            return;
        }

        if (code == null || code.isBlank()) {
            response.setStatus(400);
            response.getWriter().write("Missing code");
            return;
        }

        OidcTokens tokens = oidcService.exchangeCodeForTokens(request, code);
        if (tokens.getIdToken() == null || tokens.getIdToken().isBlank()) {
            response.setStatus(401);
            response.getWriter().write("Missing id_token");
            return;
        }

        Map<String, Object> claims = oidcService.parseAndValidateIdTokenClaims(request, tokens.getIdToken());
        Map<String, Object> userInfo = Map.of();
        if (tokens.getAccessToken() != null && !tokens.getAccessToken().isBlank()) {
            userInfo = oidcService.fetchUserInfo(tokens.getAccessToken());
        }

        String appSessionId = UUID.randomUUID().toString();
        UserSession userSession = UserSession.from(appSessionId, claims, userInfo, tokens.getAccessToken());

        session.setAttribute("USER_SESSION", userSession);
        session.removeAttribute("OIDC_STATE");
        session.removeAttribute("OIDC_NONCE");
        session.removeAttribute("OIDC_CODE_VERIFIER");

        response.sendRedirect("/");
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        response.sendRedirect("/");
    }

    @GetMapping("/me")
    public Object me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return Map.of("authenticated", false);
        Object us = session.getAttribute("USER_SESSION");
        if (!(us instanceof UserSession userSession)) return Map.of("authenticated", false);

        Map<String, Object> out = new LinkedHashMap<>();
        out.put("authenticated", true);
        out.put("sessionId", userSession.getSessionId());
        out.put("sub", userSession.getSubject());
        out.put("name", userSession.getName());
        out.put("email", userSession.getEmail());
        out.put("authenticatedAt", userSession.getAuthenticatedAt().toString());
        out.put("idTokenClaims", userSession.getIdTokenClaims());
        out.put("userInfo", userSession.getUserInfo());
        return out;
    }
}

@Component
class RequireAuthFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (path.startsWith("/login") || path.startsWith("/oidc/") || path.startsWith("/error") || path.startsWith("/me")) {
            filterChain.doFilter(request, response);
            return;
        }

        if (path.startsWith("/static/") || path.startsWith("/css/") || path.startsWith("/js/") || path.startsWith("/images/")) {
            filterChain.doFilter(request, response);
            return;
        }

        HttpSession session = request.getSession(false);
        boolean authed = session != null && session.getAttribute("USER_SESSION") instanceof UserSession;

        if (!authed) {
            response.sendRedirect("/login");
            return;
        }

        filterChain.doFilter(request, response);
    }
}